function normalizeSavedDataForV1(){
  const normalizeItem=(r)=>{
    if(!r || typeof r!=='object') return r;
    const name=String(r.item||'').trim().toLowerCase();
    if((name==='drywall repair' || name==='4x4 drywall repair' || name==="4' x 4' drywall repair") && String(r.category||'').trim().toLowerCase()==='repairs'){
      return {...r,item:"4' x 4' Drywall Repair",category:'Repairs',cost:700};
    }
    return r;
  };
  const mergeDupes=(arr)=>{
    const map=new Map();
    (Array.isArray(arr)?arr:[]).map(normalizeItem).forEach(r=>{
      if(!r) return;
      const key=String(r.item||'').trim().toLowerCase()+'|'+String(r.category||'').trim().toLowerCase()+'|'+Number(r.cost||0);
      if(map.has(key)) map.get(key).qty=(Number(map.get(key).qty)||0)+(Number(r.qty)||0);
      else map.set(key,{...r,qty:Number(r.qty)||0});
    });
    return [...map.values()].filter(r=>(Number(r.qty)||0)>0);
  };
  try{ selected=mergeDupes(selected); localStorage.setItem('vh_selected', JSON.stringify(selected)); }catch(e){}
  try{
    const projects=JSON.parse(localStorage.getItem('vh_savedProjects') || '[]');
    let changed=false;
    projects.forEach(p=>{ if(Array.isArray(p.selected)){ p.selected=mergeDupes(p.selected); changed=true; }});
    if(changed) localStorage.setItem('vh_savedProjects', JSON.stringify(projects));
  }catch(e){}
}
